import sys

def merge(a, b):
    i = j = 0
    n, m = len(a), len(b)
    res = []
    while i < n and j < m:
        if a[i] <= b[j]:
            res.append(a[i]); i += 1
        else:
            res.append(b[j]); j += 1
    if i < n:
        res.extend(a[i:])
    if j < m:
        res.extend(b[j:])
    return res

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        a = [int(next(it)) for _ in range(n)]
        m = int(next(it))
        b = [int(next(it)) for _ in range(m)]
        merged = merge(a, b)
        out_lines.append(' '.join(map(str, merged)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

